        <div
  class="widget eps-opinion-popup-widget"
  data-widget="EParticipationOpinionPopupWidget"
>
  <!-- Trigger Button -->
  <div class="eps-opinion-trigger-wrapper">
    <p class="social-content-share-widget-title ">&nbsp;</p>
    <!-- Removed ID to support multiple instances -->
    <button type="button" class="eps-opinion-btn">
      <span></span>
      <span>আপনার মতামত প্রদান করুন</span>
      <i class="ph ph-chat-circle-text"></i>
    </button>
  </div>

  <!-- Modal -->
  <!-- Removed ID to support multiple instances -->
  <div class="eps-opinion-modal" aria-hidden="true">
    <div class="eps-opinion-modal-overlay"></div>
    <div class="eps-opinion-modal-container">
      <div class="eps-opinion-modal-header">
        <h3>আপনার মতামত প্রদান করুন</h3>
        <button type="button" class="eps-opinion-close" aria-label="Close">
          <i class="ph ph-x"></i>
        </button>
      </div>

      <div class="eps-opinion-modal-body">
        <div
  class="widget eps-opinion-form-widget"
  data-widget="EParticipationOpinionFormWidget"
>
  <div class="unique-category-container">
    <form id="opinionForm" class="opinion-form" enctype="multipart/form-data">
      <!-- We allow an external hidden input or radio group to set this, but default here -->
      <input type="hidden" name="opinionType" value="suggestion" />

      <div>
        <label class="form-label">আপনার নাম</label>
        <input
          name="name"
          type="text"
          placeholder="আপনার নাম লিখুন"
        />
        <small class="error-message" hidden>
          নাম অবশ্যই দিতে হবে
        </small>
      </div>

      <div>
        <label class="form-label">আপনার ইমেইল</label>
        <input
          name="email"
          type="email"
          placeholder="আপনার ইমেইল লিখুন"
        />
        <small class="error-message" hidden>
          সঠিক ইমেইল দিন
        </small>
      </div>

      <div>
        <label class="form-label">আপনার যোগাযোগ নম্বর</label>
        <input
          name="phone"
          type="tel"
          placeholder="আপনার যোগাযোগ নম্বর লিখুন"
        />
        <small class="error-message" hidden>
          সঠিক ফোন নম্বর দিন (যেমন 017XXXXXXXX)
        </small>
      </div>

      <div>
        <label class="form-label">আপনার মতামত</label>
        <textarea name="body" id="popupEditor"></textarea>
        <small class="error-message" hidden>
          মতামত কমপক্ষে ২০ অক্ষরের হতে হবে
        </small>
      </div>

      <div>
        <label class="form-label"
          >Attachment (jpg, jpeg, png, pdf • max 2 MB)</label
        >
        <input name="attachment" type="file" accept=".jpg,.jpeg,.png,.pdf" />
        <small class="error-message" hidden>
          Invalid file. Allowed: JPG, JPEG, PNG, PDF up to 2MB
        </small>
      </div>

      <div>
        <button type="submit" id="popupSubmitBtn">জমা দিন</button>
      </div>
    </form>
  </div>

  <!-- Ensure CKEditor is available if not loaded globally -->
  <script src="https://cdn.ckeditor.com/ckeditor5/41.4.2/classic/ckeditor.js"></script>
</div>

      </div>
    </div>
  </div>
</div>

